/**
 * Custom ERC-20 bridging test scenarios -- defined ONCE, run by every adapter.
 *
 * Ported from packages/sdk/tests/integration/customerc20.test.ts.
 * Uses the TestHarness interface for signing/sending and the
 * provider-agnostic core functions for all bridging logic.
 */
import { describe, it, expect } from 'vitest'
import type { TestHarness, TestConfig } from '../harness'
import {
  getApproveTokenRequest,
  getErc20DepositRequest,
  getErc20WithdrawalRequest,
  getParentGatewayAddress,
  getChildGatewayAddress,
  getChildErc20Address,
  getParentToChildMessages,
  getChildToParentMessages,
  getRegisterCustomTokenRequest,
  estimateSubmissionFee,
  estimateMaxFeePerGas,
  getExecuteRequest,
  getSendProps,
  ParentToChildMessageStatus,
  ChildToParentMessageStatus,
  assertArbitrumNetworkHasTokenBridge,
  ArbitrumContract,
  ERC20Abi,
  getChildToParentEvents,
  type ArbitrumNetwork,
} from '../../../src'

/**
 * TestOrbitCustomTokenL1 bytecode from @arbitrum/token-bridge-contracts.
 * Used for orbit tests (L3 chains with custom fee tokens).
 * Constructor: (address _gateway, address _router)
 */
const TEST_ORBIT_CUSTOM_TOKEN_L1_BYTECODE =
  ''

/**
 * TestCustomTokenL1 bytecode from @arbitrum/token-bridge-contracts.
 * Constructor: (address _gateway, address _router)
 */
const TEST_CUSTOM_TOKEN_L1_BYTECODE =
  ''

/**
 * TestArbCustomToken bytecode from @arbitrum/token-bridge-contracts.
 * Constructor: (address _l2Gateway, address _l1Address)
 */
const TEST_ARB_CUSTOM_TOKEN_BYTECODE =
  ''

/** Minimal ABI for TestCustomTokenL1 (has mint() with no args). */
const TestCustomTokenL1Abi = [
  ...ERC20Abi,
  {
    inputs: [],
    name: 'mint',
    outputs: [],
    stateMutability: 'nonpayable',
    type: 'function',
  },
] as const

/** Amount used for ERC-20 deposits */
const DEPOSIT_AMOUNT = 100n

/** Amount used for ERC-20 withdrawals */
const WITHDRAWAL_AMOUNT = 10n

/** Delay between mining attempts (ms) */
const MINE_INTERVAL_MS = 500

/** Wait helper */
function wait(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms))
}

/**
 * ABI-encode two address values and append to bytecode as constructor args.
 * Addresses are left-padded to 32 bytes each.
 */
function appendConstructorArgs(
  bytecode: string,
  addr1: string,
  addr2: string
): string {
  const pad = (addr: string) =>
    addr.replace(/^0x/, '').toLowerCase().padStart(64, '0')
  const base = bytecode.startsWith('0x') ? bytecode : `0x${bytecode}`
  return base + pad(addr1) + pad(addr2)
}

/**
 * Read the ERC-20 balance of an address using the ArbitrumContract helper.
 */
async function getTokenBalance(
  harness: TestHarness,
  rpcUrl: string,
  tokenAddress: string,
  account: string
): Promise<bigint> {
  const provider = harness.createProvider(rpcUrl)
  const token = new ArbitrumContract(ERC20Abi, tokenAddress).connect(provider)
  const [balance] = await token.read('balanceOf', [account])
  return balance as bigint
}

/**
 * Mine blocks by sending self-transfers on a given chain.
 */
async function mineUntilStop(
  harness: TestHarness,
  rpcUrl: string,
  key: string,
  state: { mining: boolean }
): Promise<void> {
  const addr = harness.getAddress(key)
  while (state.mining) {
    try {
      await harness.sendEth(key, rpcUrl, addr, 0n)
    } catch {
      // ignore transient failures
    }
    await wait(MINE_INTERVAL_MS)
  }
}

/**
 * Get the parent and child RPC URLs and the active network
 * based on whether this is an orbit test.
 */
function getNetworkContext(config: TestConfig): {
  parentRpcUrl: string
  childRpcUrl: string
  network: ArbitrumNetwork
} {
  if (config.isOrbitTest && config.l3Network) {
    return {
      parentRpcUrl: config.l2RpcUrl,
      childRpcUrl: config.l3RpcUrl,
      network: config.l3Network,
    }
  }
  return {
    parentRpcUrl: config.l1RpcUrl,
    childRpcUrl: config.l2RpcUrl,
    network: config.l2Network,
  }
}

/**
 * Register all Custom ERC-20 bridging test scenarios.
 */
export function customErc20Scenarios(
  harness: TestHarness,
  config: TestConfig
): void {
  const { parentRpcUrl, childRpcUrl, network } = getNetworkContext(config)

  describe('Custom ERC-20 Bridging', () => {
    // Shared state: deployed custom token addresses, set during registration
    let parentTokenAddress: string
    let childTokenAddress: string

    // Deploy and register tokens once before all tests
    let setupDone: Promise<void>
    const ensureSetup = () => {
      if (!setupDone) {
        setupDone = (async () => {
          assertArbitrumNetworkHasTokenBridge(network)

          const testAddr = harness.getAddress(config.funnelKey)

          // 1. Deploy TestCustomTokenL1 (or TestOrbitCustomTokenL1) on parent chain
          const parentBytecodeBase = config.isOrbitTest
            ? TEST_ORBIT_CUSTOM_TOKEN_L1_BYTECODE
            : TEST_CUSTOM_TOKEN_L1_BYTECODE
          const l1Bytecode = appendConstructorArgs(
            parentBytecodeBase,
            network.tokenBridge.parentCustomGateway,
            network.tokenBridge.parentGatewayRouter
          )
          const { address: parentAddr } = await harness.deployContract(
            config.funnelKey,
            parentRpcUrl,
            l1Bytecode
          )
          parentTokenAddress = parentAddr

          // 2. Deploy TestArbCustomToken on child chain
          // Constructor: (childCustomGateway, parentTokenAddress)
          const l2Bytecode = appendConstructorArgs(
            TEST_ARB_CUSTOM_TOKEN_BYTECODE,
            network.tokenBridge.childCustomGateway,
            parentTokenAddress
          )
          const { address: childAddr } = await harness.deployContract(
            config.funnelKey,
            childRpcUrl,
            l2Bytecode
          )
          childTokenAddress = childAddr

          // 3. Mint tokens on the parent custom token
          const mintContract = new ArbitrumContract(
            TestCustomTokenL1Abi,
            parentTokenAddress
          )
          const mintTx = mintContract.encodeWrite('mint', [])
          await harness.sendTransaction(config.funnelKey, parentRpcUrl, mintTx)

          // 4. Register the custom token pair
          const parentProvider = harness.createProvider(parentRpcUrl)
          const childProvider = harness.createProvider(childRpcUrl)

          // Estimate gas for the two retryable tickets
          const maxFeePerGas = await estimateMaxFeePerGas(childProvider)
          const maxSubmissionCostForCustomBridge =
            await estimateSubmissionFee(parentProvider, network, 256)
          const maxSubmissionCostForRouter =
            await estimateSubmissionFee(parentProvider, network, 256)

          // Estimate gas limits by simulating the calls via NodeInterface
          // Use generous defaults for testnode
          const maxGasForCustomBridge = 1_000_000n
          const maxGasForRouter = 1_000_000n

          const valueForGateway =
            maxGasForCustomBridge * maxFeePerGas +
            maxSubmissionCostForCustomBridge
          const valueForRouter =
            maxGasForRouter * maxFeePerGas + maxSubmissionCostForRouter

          const regTx = getRegisterCustomTokenRequest({
            network,
            parentTokenAddress,
            childTokenAddress,
            from: testAddr,
            maxSubmissionCostForCustomBridge,
            maxSubmissionCostForRouter,
            maxGasForCustomBridge,
            maxGasForRouter,
            gasPriceBid: maxFeePerGas,
            valueForGateway,
            valueForRouter,
            creditBackAddress: testAddr,
          })
          const regReceipt = await harness.sendTransaction(
            config.funnelKey,
            parentRpcUrl,
            regTx
          )
          expect(regReceipt.status).toBe(1)

          // 5. Wait for 2 parent-to-child messages (setToken + setGateway)
          const messages = getParentToChildMessages(
            regReceipt,
            childProvider,
            network
          )
          expect(messages.length).toBe(2)

          const setTokenResult = await messages[0].waitForStatus(120_000)
          expect(setTokenResult.status).toBe(
            ParentToChildMessageStatus.REDEEMED
          )

          const setGatewayResult = await messages[1].waitForStatus(120_000)
          expect(setGatewayResult.status).toBe(
            ParentToChildMessageStatus.REDEEMED
          )
        })()
      }
      return setupDone
    }

    // ---------------------------------------------------------------
    // Test 3.1: register custom token
    // ---------------------------------------------------------------
    it(
      'register custom token',
      { timeout: 300_000 },
      async () => {
        await ensureSetup()

        assertArbitrumNetworkHasTokenBridge(network)

        const parentProvider = harness.createProvider(parentRpcUrl)
        const childProvider = harness.createProvider(childRpcUrl)

        // Verify the parent gateway is the custom gateway
        const parentGateway = await getParentGatewayAddress(
          parentTokenAddress,
          parentProvider,
          network
        )
        expect(parentGateway.toLowerCase()).toBe(
          network.tokenBridge.parentCustomGateway.toLowerCase()
        )

        // Verify the child gateway is the custom gateway
        const childGateway = await getChildGatewayAddress(
          parentTokenAddress,
          childProvider,
          network
        )
        expect(childGateway.toLowerCase()).toBe(
          network.tokenBridge.childCustomGateway.toLowerCase()
        )
      }
    )

    // ---------------------------------------------------------------
    // Test 3.2: deposit custom ERC-20
    // ---------------------------------------------------------------
    it(
      'deposit custom ERC-20',
      { timeout: 300_000 },
      async () => {
        await ensureSetup()

        assertArbitrumNetworkHasTokenBridge(network)

        const testAddr = harness.getAddress(config.funnelKey)
        const parentProvider = harness.createProvider(parentRpcUrl)
        const childProvider = harness.createProvider(childRpcUrl)

        // Step 1: Approve the token for the custom gateway
        const approveTx = await getApproveTokenRequest({
          network,
          erc20ParentAddress: parentTokenAddress,
          from: testAddr,
          parentProvider,
        })
        const approveReceipt = await harness.sendTransaction(
          config.funnelKey,
          parentRpcUrl,
          approveTx
        )
        expect(approveReceipt.status).toBe(1)

        // Verify the custom gateway is used (not standard)
        const parentGateway = await getParentGatewayAddress(
          parentTokenAddress,
          parentProvider,
          network
        )
        expect(parentGateway.toLowerCase()).toBe(
          network.tokenBridge.parentCustomGateway.toLowerCase()
        )

        // Step 2: Build and send the deposit request
        const depositTx = await getErc20DepositRequest({
          network,
          erc20ParentAddress: parentTokenAddress,
          amount: DEPOSIT_AMOUNT,
          from: testAddr,
          parentProvider,
          childProvider,
          retryableGasOverrides: {
            maxSubmissionFee: { percentIncrease: 500n },
            gasLimit: { percentIncrease: 200n, min: 1_000_000n },
          },
        })
        const depositReceipt = await harness.sendTransaction(
          config.funnelKey,
          parentRpcUrl,
          depositTx
        )
        expect(depositReceipt.status).toBe(1)

        // Step 3: Wait for auto-redeem
        const messages = getParentToChildMessages(
          depositReceipt,
          childProvider,
          network
        )
        expect(messages.length).toBe(1)

        const result = await messages[0].waitForStatus(120_000)
        expect(result.status).toBe(ParentToChildMessageStatus.REDEEMED)

        // Step 4: Verify child token balance
        const childErc20Addr = await getChildErc20Address(
          parentTokenAddress,
          parentProvider,
          network
        )
        const childBalance = await getTokenBalance(
          harness,
          childRpcUrl,
          childErc20Addr,
          testAddr
        )
        expect(childBalance).toBe(DEPOSIT_AMOUNT)

        // Step 5: Verify custom gateway was used on child chain
        const childGateway = await getChildGatewayAddress(
          parentTokenAddress,
          childProvider,
          network
        )
        expect(childGateway.toLowerCase()).toBe(
          network.tokenBridge.childCustomGateway.toLowerCase()
        )
      }
    )

    // ---------------------------------------------------------------
    // Test 3.3: withdraw custom ERC-20
    // ---------------------------------------------------------------
    it(
      'withdraw custom ERC-20',
      { timeout: 300_000 },
      async () => {
        await ensureSetup()

        assertArbitrumNetworkHasTokenBridge(network)

        const testAddr = harness.getAddress(config.funnelKey)
        const parentProvider = harness.createProvider(parentRpcUrl)
        const childProvider = harness.createProvider(childRpcUrl)

        // Ensure we have tokens on child chain (deposit test should have run)
        const childErc20Addr = await getChildErc20Address(
          parentTokenAddress,
          parentProvider,
          network
        )

        let childBalanceBefore = await getTokenBalance(
          harness,
          childRpcUrl,
          childErc20Addr,
          testAddr
        )

        // If no child balance, deposit first
        if (childBalanceBefore === 0n) {
          const approveTx = await getApproveTokenRequest({
            network,
            erc20ParentAddress: parentTokenAddress,
            from: testAddr,
            parentProvider,
          })
          await harness.sendTransaction(
            config.funnelKey,
            parentRpcUrl,
            approveTx
          )

          const depositTx = await getErc20DepositRequest({
            network,
            erc20ParentAddress: parentTokenAddress,
            amount: DEPOSIT_AMOUNT,
            from: testAddr,
            parentProvider,
            childProvider,
            retryableGasOverrides: {
              maxSubmissionFee: { percentIncrease: 500n },
              gasLimit: { percentIncrease: 200n, min: 1_000_000n },
            },
          })
          const depositReceipt = await harness.sendTransaction(
            config.funnelKey,
            parentRpcUrl,
            depositTx
          )

          const messages = getParentToChildMessages(
            depositReceipt,
            childProvider,
            network
          )
          await messages[0].waitForStatus(120_000)

          childBalanceBefore = await getTokenBalance(
            harness,
            childRpcUrl,
            childErc20Addr,
            testAddr
          )
        }

        expect(childBalanceBefore).toBeGreaterThan(0n)

        // Build and send the withdrawal on the child chain
        const withdrawTx = getErc20WithdrawalRequest({
          network,
          erc20ParentAddress: parentTokenAddress,
          amount: WITHDRAWAL_AMOUNT,
          destinationAddress: testAddr,
          from: testAddr,
        })

        const withdrawReceipt = await harness.sendTransaction(
          config.funnelKey,
          childRpcUrl,
          withdrawTx
        )
        expect(withdrawReceipt.status).toBe(1)

        // Verify child balance decreased
        const childBalanceAfter = await getTokenBalance(
          harness,
          childRpcUrl,
          childErc20Addr,
          testAddr
        )
        expect(childBalanceAfter).toBe(childBalanceBefore - WITHDRAWAL_AMOUNT)

        // Get child-to-parent messages
        const withdrawMessages = getChildToParentMessages(
          withdrawReceipt,
          parentProvider,
          network
        )
        expect(withdrawMessages.length).toBeGreaterThanOrEqual(1)

        const withdrawMessage = withdrawMessages[0]
        expect(withdrawMessage).toBeDefined()

        // Verify the L2ToL1Tx events
        const withdrawEvents = getChildToParentEvents(withdrawReceipt)
        expect(withdrawEvents.length).toBe(1)

        // Check initial status is UNCONFIRMED
        const initialStatus = await withdrawMessage.status(
          network,
          childProvider
        )
        expect(initialStatus).toBe(ChildToParentMessageStatus.UNCONFIRMED)

        // Get parent token balance before execution
        const parentBalanceBefore = await getTokenBalance(
          harness,
          parentRpcUrl,
          parentTokenAddress,
          testAddr
        )

        // Mine blocks on both chains while waiting for assertion confirmation
        const state = { mining: true }
        await Promise.race([
          mineUntilStop(harness, parentRpcUrl, config.funnelKey, state),
          mineUntilStop(harness, childRpcUrl, config.funnelKey, state),
          withdrawMessage.waitUntilReadyToExecute(
            network,
            childProvider,
            500
          ),
        ])
        state.mining = false

        // Verify status is now CONFIRMED
        const confirmedStatus = await withdrawMessage.status(
          network,
          childProvider
        )
        expect(confirmedStatus).toBe(ChildToParentMessageStatus.CONFIRMED)

        // Get the outbox proof
        const { sendRootSize } = await getSendProps(
          parentProvider,
          childProvider,
          withdrawMessage.event,
          network
        )
        expect(sendRootSize).toBeDefined()

        const proof = await withdrawMessage.getOutboxProof(
          childProvider,
          sendRootSize!
        )

        // Build and send the execute request on the parent chain
        const executeTx = getExecuteRequest(
          withdrawMessage.event,
          proof,
          network
        )

        const executeReceipt = await harness.sendTransaction(
          config.funnelKey,
          parentRpcUrl,
          executeTx
        )
        expect(executeReceipt.status).toBe(1)

        // Verify status is now EXECUTED
        const executedStatus = await withdrawMessage.status(
          network,
          childProvider
        )
        expect(executedStatus).toBe(ChildToParentMessageStatus.EXECUTED)

        // Verify the parent chain received the tokens
        const parentBalanceAfter = await getTokenBalance(
          harness,
          parentRpcUrl,
          parentTokenAddress,
          testAddr
        )
        expect(parentBalanceAfter).toBe(
          parentBalanceBefore + WITHDRAWAL_AMOUNT
        )
      }
    )

    // ---------------------------------------------------------------
    // Test 3.4: deposit custom ERC-20 with extra ETH
    // ---------------------------------------------------------------
    it.skip('deposit custom ERC-20 with extra ETH', async () => {
      // TODO: Port from old SDK. Batch custom token + ETH deposit.
      // Blocked on ethDepositAmount support in getErc20DepositRequest.
    })

    // ---------------------------------------------------------------
    // Test 3.5: deposit custom ERC-20 with extra ETH to specific address
    // ---------------------------------------------------------------
    it.skip('deposit custom ERC-20 with extra ETH to specific address', async () => {
      // TODO: Port from old SDK. Same as 3.4 but with destinationAddress.
      // Blocked on ethDepositAmount support in getErc20DepositRequest.
    })
  })
}
